import { createRootRoute, Link, Outlet } from '@tanstack/react-router'

export const Route = createRootRoute({
  component: RootLayout,
})

function RootLayout() {
  return (
    <div>
      <nav>
        <Link to="/search">Search</Link>
      </nav>
      <Outlet />
    </div>
  )
}

import { createFileRoute } from '@tanstack/react-router'

export const Route = createFileRoute('/')({
  component: HomePage,
})

function HomePage() {
  return (
    <div>
      <h1>Home</h1>
      <p>Welcome! Navigate to the search page.</p>
    </div>
  )
}

import { createFileRoute } from '@tanstack/react-router'
import { z } from 'zod'

const searchSchema = z.object({
  q: z.string().default(''),
  category: z.string().default(''),
  minPrice: z.union([z.number(), z.nan()]).default(NaN).catch(NaN),
  maxPrice: z.union([z.number(), z.nan()]).default(NaN).catch(NaN),
})

export const Route = createFileRoute('/search')({
  validateSearch: searchSchema,
  component: SearchPage,
})

function SearchPage() {
  const search = Route.useSearch()
  const navigate = Route.useNavigate()

  function updateSearch(key: string, value: string) {
    const updates: Record<string, string | number> = {}
    if (key === 'minPrice' || key === 'maxPrice') {
      const num = parseFloat(value)
      updates[key] = isNaN(num) ? NaN : num
    } else {
      updates[key] = value
    }
    navigate({ search: (prev) => ({ ...prev, ...updates }), replace: true })
  }

  return (
    <div>
      <h1>Search</h1>
      <form>
        <div>
          <label htmlFor="q">Query</label>
          <input
            name="q"
            type="text"
            value={search.q}
            onChange={(e) => updateSearch('q', e.target.value)}
          />
        </div>
        <div>
          <label htmlFor="category">Category</label>
          <input
            name="category"
            type="text"
            value={search.category}
            onChange={(e) => updateSearch('category', e.target.value)}
          />
        </div>
        <div>
          <label htmlFor="minPrice">Min Price</label>
          <input
            name="minPrice"
            type="number"
            value={isNaN(search.minPrice) ? '' : search.minPrice}
            onChange={(e) => updateSearch('minPrice', e.target.value)}
          />
        </div>
        <div>
          <label htmlFor="maxPrice">Max Price</label>
          <input
            name="maxPrice"
            type="number"
            value={isNaN(search.maxPrice) ? '' : search.maxPrice}
            onChange={(e) => updateSearch('maxPrice', e.target.value)}
          />
        </div>
      </form>
    </div>
  )
}

import { StrictMode } from 'react'
import { createRoot } from 'react-dom/client'
import { createRouter, RouterProvider } from '@tanstack/react-router'
import { routeTree } from './routeTree.gen'
import './index.css'

const router = createRouter({ routeTree })

declare module '@tanstack/react-router' {
  interface Register {
    router: typeof router
  }
}

createRoot(document.getElementById('root')!).render(
  <StrictMode>
    <RouterProvider router={router} />
  </StrictMode>,
